const { token, userId, gymId } = $input.first().json;
const secret = $env['QR_SECRET'];

if (!token || !userId || !gymId) {
  return [{ json: { valid: false, reason: 'Missing fields', userId, gymId } }];
}

try {
  // Token format: base64(payload).HMAC
  const parts = token.split('.');
  if (parts.length !== 2) return [{ json: { valid: false, reason: 'Bad token format' } }];

  const [encodedPayload, receivedSig] = parts;
  const crypto = require('crypto');
  const expectedSig = crypto.createHmac('sha256', secret).update(encodedPayload).digest('base64url');

  if (receivedSig !== expectedSig) {
    return [{ json: { valid: false, reason: 'Invalid signature', userId, gymId } }];
  }

  const payload = JSON.parse(Buffer.from(encodedPayload, 'base64url').toString('utf8'));

  // Check expiry (token valid for 30 seconds)
  const now = Date.now() / 1000;
  if (payload.exp && payload.exp < now) {
    return [{ json: { valid: false, reason: 'Token expired', userId, gymId } }];
  }

  // User in token must match request
  if (payload.uid !== userId || payload.gid !== gymId) {
    return [{ json: { valid: false, reason: 'User/gym mismatch', userId, gymId } }];
  }

  return [{ json: { valid: true, userId, gymId, payload } }];
} catch(e) {
  return [{ json: { valid: false, reason: e.message, userId, gymId } }];
}
